import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const countryCodes = [
  { code: "+1", name: "🇺🇸 United States", value: "+1" },
  { code: "+44", name: "🇬🇧 United Kingdom", value: "+44" },
  { code: "+91", name: "🇮🇳 India", value: "+91" },
  { code: "+61", name: "🇦🇺 Australia", value: "+61" },
  { code: "+81", name: "🇯🇵 Japan", value: "+81" },
  { code: "+49", name: "🇩🇪 Germany", value: "+49" },
  { code: "+33", name: "🇫🇷 France", value: "+33" },
  { code: "+86", name: "🇨🇳 China", value: "+86" },
  { code: "+7", name: "🇷🇺 Russia", value: "+7" },
  { code: "+55", name: "🇧🇷 Brazil", value: "+55" },
];

export default function Register({ onRegister }) {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: "",
    phone: "",
    email: "",
    address: "",
    otp: "",
  });
  const [selectedCountryCode, setSelectedCountryCode] = useState("+91");

  const [otpVerified, setOtpVerified] = useState(false);
  const [emailValid, setEmailValid] = useState(false);
  const [phoneValid, setPhoneValid] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);

  const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000";

  useEffect(() => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    setEmailValid(emailRegex.test(form.email));
    const phoneRegex = /^\d{10}$/;
    setPhoneValid(phoneRegex.test(form.phone));
  }, [form.email, form.phone]);

  const handleChange = (e) => {
    if (e.target.name === "phone") {
      const value = e.target.value;
      if (/^\d*$/.test(value)) {
        setForm({ ...form, [e.target.name]: value });
      }
    } else {
      setForm({ ...form, [e.target.name]: e.target.value });
    }
  };

  const handleCountryCodeChange = (e) => {
    setSelectedCountryCode(e.target.value);
  };

  const sendOtp = async () => {
    if (!phoneValid) {
      setError("Please enter a valid phone number");
      return;
    }
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const fullPhone = selectedCountryCode + form.phone;
      const res = await fetch(API_BASE + "/api/auth/send-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: fullPhone, isRegistration: true }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setOtpSent(true);
        setSuccess("OTP sent successfully! 📱");
        setTimeout(() => {
          setCurrentStep(2);
          setSuccess("");
        }, 1500);
      } else {
        setError(data.message || "Failed to send OTP");
      }
    } catch (e) {
      setError("Network error. Please try again.");
    }
    setLoading(false);
  };

  const verifyOtp = async () => {
    if (!form.otp) {
      setError("Please enter the OTP");
      return;
    }
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const fullPhone = selectedCountryCode + form.phone;
      const res = await fetch(API_BASE + "/api/auth/verify-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: fullPhone, otp: form.otp, isRegistration: true }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setOtpVerified(true);
        setSuccess("Phone verified successfully! ✅");
        setTimeout(() => {
          setCurrentStep(3);
          setSuccess("");
        }, 1500);
      } else {
        setError(data.message || "OTP verification failed");
      }
    } catch (e) {
      setError("Network error. Please try again.");
    }
    setLoading(false);
  };

  const handleSubmit = async () => {
    if (!otpVerified || !emailValid || !phoneValid) {
      setError("Please complete all validations");
      return;
    }
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const fullPhone = selectedCountryCode + form.phone;
      const { name, email, address, otp } = form;
      const res = await fetch(API_BASE + "/api/auth/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, phone: fullPhone, email, address, otp }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setSuccess("Account created successfully! 🎉");
        setTimeout(() => {
          onRegister(data.user);
        }, 2000);
      } else {
        setError(data.message || "Registration failed");
      }
    } catch (e) {
      setError("Network error. Please try again.");
    }
    setLoading(false);
  };



  const prevStep = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-background">
        <div className="floating-shapes">
          <div className="shape shape-1"></div>
          <div className="shape shape-2"></div>
          <div className="shape shape-3"></div>
        </div>
      </div>

      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="auth-icon">🏠</div>
            <h1 className="auth-title">Smart Home</h1>
            <p className="auth-subtitle">Create your account</p>
          </div>

          <div className="auth-form-container">
            {/* Step Indicator */}
            <div className="step-indicator">
              <div className={`step ${currentStep >= 1 ? 'active' : ''}`}>1</div>
              <div className={`step-line ${currentStep > 1 ? 'active' : ''}`}></div>
              <div className={`step ${currentStep >= 2 ? 'active' : ''}`}>2</div>
              <div className={`step-line ${currentStep > 2 ? 'active' : ''}`}></div>
              <div className={`step ${currentStep >= 3 ? 'active' : ''}`}>3</div>
            </div>

            {/* Step 1: Basic Info */}
            {currentStep === 1 && (
              <div className="auth-step" key="step1">
                <div className="form-section">
                  <h2 className="form-title">Personal Information</h2>
                  <p className="form-description">Let's start with your basic details</p>

                  <div className="input-group">
                    <label className="input-label">Full Name *</label>
                    <input
                      name="name"
                      placeholder="Enter your full name"
                      value={form.name}
                      onChange={handleChange}
                      className="auth-input"
                    />
                  </div>

                  <div className="input-group">
                    <label className="input-label">Phone Number *</label>
                    <div className="phone-input-container">
                      <select
                        value={selectedCountryCode}
                        onChange={handleCountryCodeChange}
                        className="country-select"
                      >
                        {countryCodes.map((country) => (
                          <option key={country.code} value={country.code}>
                            {country.name} ({country.code})
                          </option>
                        ))}
                      </select>
                      <input
                        name="phone"
                        placeholder="Enter phone number"
                        value={form.phone}
                        onChange={handleChange}
                        className="phone-input"
                        maxLength="10"
                      />
                    </div>
                  </div>

                  <button
                    onClick={sendOtp}
                    disabled={!phoneValid || !form.name || loading}
                    className={`auth-button primary ${(!phoneValid || !form.name || loading) ? 'disabled' : ''}`}
                  >
                    {loading ? (
                      <span className="button-content">
                        <div className="spinner"></div>
                        Sending OTP...
                      </span>
                    ) : (
                      <span className="button-content">
                        Send OTP 📱
                      </span>
                    )}
                  </button>
                </div>
              </div>
            )}

            {/* Step 2: OTP Verification */}
            {currentStep === 2 && (
              <div className="auth-step" key="step2">
                <div className="form-section">
                  <h2 className="form-title">Verify Phone Number</h2>
                  <p className="form-description">
                    We've sent a 4-digit code to {selectedCountryCode} {form.phone}
                  </p>

                  <div className="input-group">
                    <label className="input-label">OTP Code *</label>
                    <input
                      name="otp"
                      placeholder="Enter 4-digit code"
                      value={form.otp}
                      onChange={handleChange}
                      className="otp-input"
                      maxLength="4"
                    />
                  </div>

                  <button
                    onClick={verifyOtp}
                    disabled={loading || !form.otp || form.otp.length !== 4}
                    className={`auth-button primary ${loading || form.otp.length !== 4 ? 'disabled' : ''}`}
                  >
                    {loading ? (
                      <span className="button-content">
                        <div className="spinner"></div>
                        Verifying...
                      </span>
                    ) : (
                      <span className="button-content">
                        Verify Phone ✅
                      </span>
                    )}
                  </button>

                  <button
                    onClick={prevStep}
                    className="auth-button secondary"
                  >
                    ← Back
                  </button>
                </div>
              </div>
            )}

            {/* Step 3: Additional Info */}
            {currentStep === 3 && (
              <div className="auth-step" key="step3">
                <div className="form-section">
                  <h2 className="form-title">Additional Information</h2>
                  <p className="form-description">Almost done! Just a few more details</p>

                  <div className="input-group">
                    <label className="input-label">Email Address *</label>
                    <input
                      name="email"
                      type="email"
                      placeholder="Enter your email"
                      value={form.email}
                      onChange={handleChange}
                      className={`auth-input ${emailValid ? 'valid' : form.email ? 'invalid' : ''}`}
                    />
                  </div>

                  <div className="input-group">
                    <label className="input-label">Address</label>
                    <input
                      name="address"
                      placeholder="Enter your address"
                      value={form.address}
                      onChange={handleChange}
                      className="auth-input"
                    />
                  </div>

                  <button
                    onClick={handleSubmit}
                    disabled={!otpVerified || !emailValid || !phoneValid || loading}
                    className={`auth-button primary ${(!otpVerified || !emailValid || !phoneValid || loading) ? 'disabled' : ''}`}
                  >
                    {loading ? (
                      <span className="button-content">
                        <div className="spinner"></div>
                        Creating Account...
                      </span>
                    ) : (
                      <span className="button-content">
                        Create Account 🎉
                      </span>
                    )}
                  </button>

                  <button
                    onClick={prevStep}
                    className="auth-button secondary"
                  >
                    ← Back
                  </button>
                </div>
              </div>
            )}

            {error && (
              <div className="alert error">
                <span className="alert-icon">⚠️</span>
                {error}
              </div>
            )}

            {success && (
              <div className="alert success">
                <span className="alert-icon">✅</span>
                {success}
              </div>
            )}

            <div className="auth-footer">
              <p>Already have an account?</p>
              <button
                onClick={() => navigate('/login')}
                className="link-button"
              >
                Sign In →
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
